const doc = $input.first().json;
const confidence = doc.ai_confidence ? Math.round(doc.ai_confidence * 100) : 'N/A';
const total = doc.total_amount 
  ? new Intl.NumberFormat('en-IN', {style:'currency',currency:doc.currency||'INR'}).format(doc.total_amount)
  : 'Not extracted';

return [{
  json: {
    slack_message: [
      `📄 *Invoice Processed* — ${doc.file_name}`,
      ``,
      `*Vendor:* ${doc.vendor_name || 'Unknown'}`,
      `*Invoice #:* ${doc.invoice_number || 'Unknown'}`,
      `*Date:* ${doc.invoice_date || 'Unknown'}`,
      `*Due:* ${doc.due_date || 'Unknown'}`,
      `*Total:* ${total}`,
      `*AI Confidence:* ${confidence}%`,
      ``,
      `🔗 View full extraction: http://localhost:8001/docs#/documents/get_document_api_v1_documents__document_id__get`,
      `📊 Document ID: ${doc.id}`,
    ].join('\n'),
    document_id: doc.id,
    vendor_name: doc.vendor_name,
    total_amount: doc.total_amount,
  }
}];

const doc = $input.first().json;
console.error(`[DocAI] Extraction FAILED for document ${doc.id} (${doc.file_name}): ${doc.error_message}`);
return [{json: {status: 'logged', document_id: doc.id, error: doc.error_message}}];

const file = $input.first().json;
console.log(`[DocAI] Skipping non-PDF: ${file.name} (${file.mimeType})`);
return [{json: {skipped: true, file: file.name}}];
